SELECT comment_id, user_id, product_id, product_type, score, content, images, create_time, order_item_id, status
FROM comments
WHERE product_type = #{productType} AND product_id = #{productId} AND status = 1

    AND score = #{score}

ORDER BY create_time DESC
LIMIT #{offset}, #{size}

SELECT comment_id, user_id, product_id, product_type, score, content, images, create_time, order_item_id, status
FROM comments
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) 
FROM comments
WHERE user_id = #{userId}

SELECT comment_id, user_id, product_id, product_type, score, content, images, create_time, order_item_id, status
FROM comments
WHERE comment_id = #{commentId}
